#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.screenLayout)]
    public class ScreenLayoutOptionDropdown : OptionDropdownDefinition
    {
        public ScreenLayoutOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            if (context is IOptionContextLevel)
            {
                return false;
            }
            return base.ShouldEnable(context);
        }
        public override int GetValue(IOptionContext context)
        {
            var screenLayout = context.TryGetCachedOptionInt(LogicOptionItemID.screenLayout, out var value) ? value : Global.Options.GetScreenLayout();
            var index = Array.IndexOf(screenLayouts, screenLayout);
            if (index < 0)
            {
                index = 0;
            }
            return index;
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var localization = Global.Localization;
            for (int i = 0; i < screenLayouts.Length; i++)
            {
                var text = screenLayoutTexts[i];
                items.Add(localization.GetTextParticular(text, LogicStrings.CONTEXT_SCREEN_LAYOUT));
            }
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            var screenLayout = screenLayouts[index];
            context.CacheOptionInt(LogicOptionItemID.screenLayout, screenLayout);
            context.SetNeedReload();
        }
        [TranslateMsg("屏幕布局", LogicStrings.CONTEXT_SCREEN_LAYOUT)]
        public const string SCREEN_LAYOUT_AUTO = "自动";
        [TranslateMsg("屏幕布局", LogicStrings.CONTEXT_SCREEN_LAYOUT)]
        public const string SCREEN_LAYOUT_DESKTOP = "桌面";
        [TranslateMsg("屏幕布局", LogicStrings.CONTEXT_SCREEN_LAYOUT)]
        public const string SCREEN_LAYOUT_MOBILE = "移动";

        public static readonly int[] screenLayouts = new int[]
        {
            ScreenLayouts.AUTO,
            ScreenLayouts.DESKTOP,
            ScreenLayouts.MOBILE,
        };

        public static readonly string[] screenLayoutTexts = new string[]
        {
            SCREEN_LAYOUT_AUTO,
            SCREEN_LAYOUT_DESKTOP,
            SCREEN_LAYOUT_MOBILE,
        };
    }
}
